import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav';
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage';
import Settings from './Components/Settings';  // Import the Settings component

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const navigate = useNavigate();

  // Handle login success
  const login = () => {
    setIsAuthenticated(true);  // Set the authenticated state
    navigate('/HomePage');  // Redirect to HomePage after successful login
  };

  // Handle logout (navigate to login page)
  const logout = () => {
    setIsAuthenticated(false);  // Clear authentication state
    navigate('/Login');  // Redirect to Login page
  };

  return (
    <div className="App">
      <img src="../public/J-Test.png" alt="A green leaf beside the letter T in J-Test" />

      {isAuthenticated && <SideNav logout={logout} />}  {/* Only show the SideNav if authenticated */}

      <Routes>
        <Route path="/Login" element={<LoginPage login={login} />} />
        <Route path="/Signup" element={<SignupPage />} />
        <Route path="/HomePage" element={isAuthenticated ? <HomePage /> : <Navigate to="/Login" />} />
        <Route path="/ChatBox" element={isAuthenticated ? <ChatBox /> : <Navigate to="/Login" />} />
        <Route path="/Settings" element={isAuthenticated ? <Settings /> : <Navigate to="/Login" />} /> {/* Correct the route here */}
        <Route path="/" element={<Navigate to="/Login" />} />
      </Routes>
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
